#include <stdio.h>
#include <stdlib.h>

int comparator(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

void sortDiagonal(int mat[100][100], int n, int m, int startRow, int startCol) {
    int i = startRow, j = startCol;
    int temp[100], index = 0;

    // Collect elements along the diagonal
    while (i < n && j < m) {
        temp[index++] = mat[i][j];
        i++;
        j++;
    }

    // Sort the diagonal
    qsort(temp, index, sizeof(int), comparator);

    // Place sorted elements back into the matrix
    i = startRow;
    j = startCol;
    index = 0;
    while (i < n && j < m) {
        mat[i][j] = temp[index++];
        i++;
        j++;
    }
}

void diagonalSort(int mat[100][100], int n, int m) {
    // Sort each diagonal starting from first row
    for (int col = 0; col < m; col++) {
        sortDiagonal(mat, n, m, 0, col);
    }

    // Sort each diagonal starting from first column (excluding the main diagonal)
    for (int row = 1; row < n; row++) {
        sortDiagonal(mat, n, m, row, 0);
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int mat[100][100];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                scanf("%d", &mat[i][j]);
            }
        }
        diagonalSort(mat, n, m);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                printf("%d ", mat[i][j]);
            }
            printf("\n");
        }
    }
    return 0;
}

